rule.positive_fixture:
class MyComponent {
  constructor(emitter) {
    this.emitter = emitter;
    this.emitter.on('data', this.handleData.bind(this));
  }

  destroy() {
    // BUG: This creates a new function, doesn't remove the listener.
    this.emitter.off('data', this.handleData.bind(this));
  }

  handleData(data) {
    console.log(data);
  }
}

rule.negative_fixture:
class MyComponent {
  constructor(emitter) {
    this.emitter = emitter;
    // CORRECT: Bind once and store the reference.
    this.boundHandleData = this.handleData.bind(this);
    this.emitter.on('data', this.boundHandleData);
  }

  destroy() {
    // CORRECT: Use the stored reference to remove the listener.
    this.emitter.off('data', this.boundHandleData);
  }

  handleData(data) {
    console.log(data);
  }
}
